mapper.select:
SELECT /* /appform/mspSalePlcyInfoByOnlyOrgn : McpAppformMapper.selectMspSalePlcyInfoByOnlyOrgn 판매정책정보를 조회 : 상품과 상관없이 기관별 조회 */ PL.SALE_PLCY_CD , --판매정책코드 PL.SALE_PLCY_NM, --판매정책명 PL.SALE_STRT_DTTM, --판매시작일시 PL.SALE_END_DTTM, --판매종료일시 PL.PLCY_TYPE_CD, --정책유형코드 M:오프라인, O:온라인 PL.ORGN_TYPE, --조직유형 PL.PLCY_SCTN_CD, --정책구분코드 01:단말, 02:USIM PL.PRDT_SCTN_CD, --제품구분코 02:3G, 03:LTE PL.APPL_SCTN_CD, --적용구분코드 O:개통일, R:접수일 PL.INST_RATE, --할부이자율 PL.NEW_YN, --신규여부 PL.MNP_YN, --번호이동여부 PL.HCN_YN, --일반 기변여부 PL.HDN_YN, --우수기변여부 PL.CNFM_YN, --확정여부 PL.CNFM_ID, --확정자ID PL.CNFM_DTTM, --확정일시 PL.REGST_ID, --등록자ID PL.REGST_DTTM, --등록일시 PL.RVISN_ID, --수정자ID PL.RVISN_DTTM, --수정일시 PL.SPRT_TP, --지원금유형 ORG.ORGN_ID FROM MSP_SALE_PLCY_MST PL, MSP_SALE_ORGN_MST ORG WHERE TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN PL.SALE_STRT_DTTM AND PL.SALE_END_DTTM --판매기간 (필수) AND PL.CNFM_YN='Y' --결제 YN (필수) AND PL.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND PL.PLCY_TYPE_CD = #{plcyTypeCd} -- 오프라인:M , 직영온라인 : D AND PL.PLCY_SCTN_CD = #{plcySctnCd} -- 01:단말,02:유심 AND ORG.ORGN_ID = #{orgnId}
AND PL.PRDT_SCTN_CD = #{prdtSctnCd} -- LTE,3G
AND PL.SPRT_TP = #{sprtTp} -- KD:단말할인,PM:요금할인

SELECT /* /msp/mspSaleOrgnMst : McpMspMapper.selectMspSaleOrgnMst 판매정책정보를 조회 */ PL.SALE_PLCY_CD , --판매정책코드 PL.SALE_PLCY_NM, --판매정책명 PL.SALE_STRT_DTTM, --판매시작일시 PL.SALE_END_DTTM, --판매종료일시 PL.PLCY_TYPE_CD, --정책유형코드 M:오프라인, O:온라인 PL.ORGN_TYPE, --조직유형 PL.PLCY_SCTN_CD, --정책구분코드 01:단말, 02:USIM PL.PRDT_SCTN_CD, --제품구분코 02:3G, 03:LTE PL.APPL_SCTN_CD, --적용구분코드 O:개통일, R:접수일 PL.INST_RATE, --할부이자율 PL.NEW_YN, --신규여부 PL.MNP_YN, --번호이동여부 PL.HCN_YN, --기변여부 PL.HDN_YN, --우수기변여부 PL.CNFM_YN, --확정여부 PL.CNFM_ID, --확정자ID PL.CNFM_DTTM, --확정일시 PL.REGST_ID, --등록자ID PL.REGST_DTTM, --등록일시 PL.RVISN_ID, --수정자ID PL.RVISN_DTTM, --수정일시 PL.SPRT_TP, --지원금유형 ORG.ORGN_ID FROM MSP_SALE_PLCY_MST PL, MSP_SALE_ORGN_MST ORG, MSP_SALE_PRDT_MST PRDT WHERE TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN PL.SALE_STRT_DTTM AND PL.SALE_END_DTTM --판매기간 (필수) AND PL.CNFM_YN='Y' --결제 YN (필수)
AND PL.PLCY_TYPE_CD = #{plcyTypeCd} -- 온라인:O , 오프라인:M , 직영온라인 : D
AND PL.PRDT_SCTN_CD = #{prdtSctnCd} -- LTE,3G
AND PL.PLCY_SCTN_CD = #{plcySctnCd} -- 01:단말,02:유심
AND PRDT.PRDT_ID = #{prdtId} -- 단말기ID (자급제인 경우는 SKIP 처리)
AND PL.SPRT_TP = #{sprtTp} -- KD:단말할인,PM:요금할인
AND ORG.ORGN_ID = #{orgnId}
AND PL.SALE_PLCY_NM LIKE #{salePlcyNm}
AND PL.SALE_PLCY_CD = #{salePlcyCd}
AND PL.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND PL.SALE_PLCY_CD = PRDT.SALE_PLCY_CD AND ORG.SALE_PLCY_cD = PRDT.SALE_PLCY_CD

SELECT /* /msp/mspSalePrdMst : McpMspMapper.selectMspSalePrdMst 판매중인 상품정보를 조회 */ SALE_PLCY_CD, --판매정책코드 PRDT_ID, --제품ID OLD_YN, --중고여부 NEW_CMSN_AMT, --신규수수료 MNP_CMSN_AMT, --MNP수수료 HCN_CMSN_AMT, --기변수수료 REGST_ID, --등록자ID REGST_DTTM, --등록일시 RVISN_ID, --수정자ID RVISN_DTTM --수정일시 FROM MSP_SALE_PRDT_MST WHERE SALE_PLCY_CD = #{salePlcyCd}
AND PRDT_ID = #{prdtId} -- (자급제인 경우는 SKIP 처리)
AND ROWNUM = 1 -- (자급제인 경우는 1개만 조회)
